insert  into `p_email_record`(`id`,`campaign_id`,`company_id`,`contact_id`,`template_id`,`in_reply_to_email_id`,`recipient_email`,`subject`,`content`,`status`,`sent_at`,`opened_at`,`replied_at`,`reply_content`,`error_message`,`tracking_id`,`message_id`,`created_at`) values (1,NULL,1,NULL,1,NULL,'liangkunyou@126.com','Professional Auto Parts Manufacturer from China - [Your Company]','<p>Dear Sir/Madam,</p>\n<p>I hope this email finds you well.</p>\n<p>I am writing to introduce Your Company Name, a professional automotive parts manufacturer based in China with over [X] years of experience.</p>\n<p><strong>Our main products include:</strong></p>\n<ul>\n<li>Exterior Parts: Bumpers, Grilles, Mirror Covers, Fenders</li>\n<li>Interior Parts: Dashboards, Door Panels, Trim</li>\n<li>Structural Parts: Body Panels, Frames</li>\n</ul>\n<p>We currently supply to distributors in Southeast Asia and would love to explore partnership opportunities with your company.</p>\n<p>Would you be interested in receiving our product catalog and price list?</p>\n<p>Best regards,<br/>Your Name<br/>Sales Manager<br/>[Company]<br/>WhatsApp: +86-xxx-xxxx-xxxx</p>','Sent','2026-06-25 20:48:08',NULL,NULL,NULL,NULL,'4a450356-0a73-499c-87cf-85f0985b7bc9','<252703040.0.1782391686651@dennis>','2026-06-25 20:48:06');
